using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now respects the UTF-8 flag, which changes
        // how non-ASCII names are encoded. Our legacy Java consumer expects
        // Shift-JIS, so we open the archive with an explicit encoding.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var stream = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(stream, ZipArchiveMode.Create, leaveOpen: false, entryNameEncoding: shiftJis);
        archive.CreateEntry("Ńā¼ŃāØŃā╝Ńāł/µ£łµ¼Ī.csv");  // Japanese path
        archive.CreateEntry("donn├®es/r├®sum├®.txt"); // French accented
    }
}

